export const formatNumber = (value?: number | null): string => {
	if (!isNumber(value)) {
		return;
	}

	const stringValue = String(value);
	const intValue = Number.parseInt(stringValue);

	// если в строке больше 6 символов - округляем до миллионов
	if (stringValue.length > 6) {
		return calcFormatted(intValue, 1_000_000) + 'M';
	}

	// если в строке больше 3 символов - округляем до тысяч
	if (stringValue.length > 3) {
		return calcFormatted(intValue, 1000) + 'K';
	}

	return intValue.toString();
};

const calcFormatted = (intValue: number, multiplier: number): string => {
	const abs = Math.abs(intValue) || 0;

	const formattedValue = `${Math.sign(intValue) * Number.parseFloat((abs / multiplier).toFixed(1))}`;
	return formattedValue.replace('.', ',');
};

export const isNumber = (value?: number | null): boolean => typeof value === 'number';
